/**
 * jquery.jConveyorTicker.min.js — Minimal news ticker plugin
 * Duplicates the <ul> content to create a seamless loop.
 * CSS animation handles the scrolling (see jConveyorTicker.css).
 */
(function ($) {
    $.fn.jConveyorTicker = function (options) {
        return this.each(function () {
            var $container = $(this);
            var $list = $container.find('ul');
            if (!$list.length || !$list.children().length) return;

            // Duplicate items for seamless infinite scroll
            var $items = $list.children().clone();
            $list.append($items);
        });
    };

    // Auto-init on document ready
    $(function () {
        $('.js-conveyor-example').jConveyorTicker();
    });
})(jQuery);